import React, { createContext, useState, useContext, useEffect } from 'react';

const ProductContext = createContext();

export const ProductProvider = ({ children }) => {
  const [products, setProducts] = useState(() => {
    const savedProducts = localStorage.getItem('products');
    return savedProducts ? JSON.parse(savedProducts) : [
      { id: 1, name: 'Mevalar toplami', price: 45000, stock: 50, image: 'https://images.unsplash.com/photo-1610832958506-aa56368176cf?auto=format&fit=crop&q=80&w=400', description: 'Yangicha saralangan mevalar to\'plami.' },
      { id: 2, name: 'Sabzavotlar seti', price: 32000, stock: 120, image: 'https://images.unsplash.com/photo-1566385101042-1a0aa0c12e8c?auto=format&fit=crop&q=80&w=400', description: 'Sifatli va yangi sabzavotlar to\'plami.' },
      { id: 3, name: 'Sut mahsulotlari', price: 12500, stock: 45, image: 'https://images.unsplash.com/photo-1550583724-125581fe2f8a?auto=format&fit=crop&q=80&w=400', description: 'Tabiiy sut va sut mahsulotlari.' },
    ];
  });

  const [staff, setStaff] = useState(() => {
    const savedStaff = localStorage.getItem('staff');
    return savedStaff ? JSON.parse(savedStaff) : [];
  });

  const [user, setUser] = useState(() => {
    const savedUser = localStorage.getItem('user');
    return savedUser ? JSON.parse(savedUser) : null;
  });

  useEffect(() => {
    localStorage.setItem('products', JSON.stringify(products));
  }, [products]);

  useEffect(() => {
    localStorage.setItem('staff', JSON.stringify(staff));
  }, [staff]);

  useEffect(() => {
    if (user) {
      localStorage.setItem('user', JSON.stringify(user));
    } else {
      localStorage.removeItem('user');
    }
  }, [user]);

  const addProduct = (newProduct) => {
    setProducts((prev) => [...prev, { ...newProduct, id: Date.now() }]);
  };

  const updateProduct = (id, updatedProduct) => {
    setProducts((prev) => 
      prev.map((product) => (product.id === id ? { ...updatedProduct, id } : product))
    );
  };

  const deleteProduct = (id) => {
    setProducts((prev) => prev.filter((product) => product.id !== id));
  };

  const addStaff = (email, password) => {
    const exists = staff.find(s => s.email === email);
    if (exists) {
      alert('Bu email bilan foydalanuvchi allaqachon mavjud!');
      return false;
    }
    const newStaff = { id: Date.now(), email, password, role: 'staff' };
    setStaff([...staff, newStaff]);
    return true;
  };

  const deleteStaff = (id) => {
    setStaff(staff.filter(s => s.id !== id));
  };

  const updateUser = (updatedData) => {
    setUser((prev) => ({ ...prev, ...updatedData }));
  };

  const login = (email, password) => {
    if (email === 'admin@gmail.com' && password === 'admin123') {
      const adminUser = { email, role: 'admin', password: 'admin123' };
      setUser(adminUser);
      return adminUser;
    }

    const foundUser = staff.find(s => s.email === email && s.password === password);
    if (foundUser) {
      const loggedInUser = { email: foundUser.email, role: foundUser.role, name: foundUser.name, password: foundUser.password };
      setUser(loggedInUser);
      return loggedInUser;
    }

    return null;
  };

  const registerUser = (userData) => {
    const exists = staff.find(s => s.email === userData.email);
    if (exists) {
      alert('Bu email bilan foydalanuvchi allaqachon mavjud!');
      return null;
    }

    const newUser = { 
      id: Date.now(), 
      email: userData.email, 
      password: userData.password, 
      role: 'admin', 
      name: `${userData.firstName} ${userData.lastName}`
    };

    setStaff([...staff, newUser]);

    const loggedInUser = { email: newUser.email, role: newUser.role, name: newUser.name, password: newUser.password };
    setUser(loggedInUser);

    return loggedInUser;
  };

  const logout = () => {
    setUser(null);
  };

  return (
    <ProductContext.Provider value={{ 
      products, 
      addProduct, 
      updateProduct,
      deleteProduct,
      staff, 
      addStaff, 
      deleteStaff, 
      user, 
      updateUser,
      login, 
      logout,
      registerUser
    }}>
      {children}
    </ProductContext.Provider>
  );
};

export const useProducts = () => useContext(ProductContext);
